1	// claim-office.ts
2	
3	export type Customer = {
4	  yearsWithMHPCO: number;
5	  previousContracts?: number;
6	};
7	
8	export type Item = {
9	  type: string;
10	  material?: string;
11	  enchantment?: number;
12	  cursed?: boolean;
13	};
14	
15	export type QuoteInput = {
16	  customer: Customer;
17	  items: Item[];
18	};
19	
20	const PROCESSING_FEE = 5;
21	const FIRST_INSURANCE_RATE = 0.1;
22	const SWORD_BASE_PREMIUM = 100;
23	const AMULET_BASE_PREMIUM = 60;
24	
25	export function quote(input: QuoteInput): number {
26	  if (input.items.length === 0) return PROCESSING_FEE;
27	  const item = input.items[0];
28	  const itemBase = item.type === "amulet" ? AMULET_BASE_PREMIUM : SWORD_BASE_PREMIUM;
29	  const policyBase = itemBase;
30	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
31	  return policyBase + firstInsuranceSurcharge + PROCESSING_FEE;
32	}
33

1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // ===== Quote: empty and processing fee =====
7	  it("empty item list yields premium of 5 G (processing fee only)", () => {
8	    expect(quote({ customer: { yearsWithMHPCO: 0, previousContracts: 0 }, items: [] })).toBe(5);
9	  });
10	
11	  // ===== Quote: single item base premiums (no modifiers, follow-up contract to neutralize first-insurance) =====
12	  // Use a long-standing customer's follow-up contract OR show base via integration.
13	  // We start with the simplest: single-item premiums combining base + first-insurance for a newcomer with no history.
14	  it("newcomer single sword (steel, enchantment 0, not cursed) yields premium 115 G (100 base + 10 first-insurance + 5 fee)", () => {
15	    expect(
16	      quote({
17	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
18	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
19	      })
20	    ).toBe(115);
21	  });
22	  it("newcomer single amulet yields premium 71 G (60 base + 6 first-insurance + 5 fee)", () => {
23	    expect(
24	      quote({
25	        customer: { yearsWithMHPCO: 0, previousContracts: 0 },
26	        items: [{ type: "amulet" }],
27	      })
28	    ).toBe(71);
29	  });
30	  it.todo("newcomer single staff yields premium 93 G (80 base + 8 first-insurance + 5 fee)");
31	  it.todo("newcomer single potion yields premium 49 G (40 base + 4 first-insurance + 5 fee)");
32	  it.todo("newcomer single rune yields premium 33 G (25 base + 3 first-insurance + 5 fee, rounded up)");
33	
34	  // ===== Quote: component blocks =====
35	  it.todo("2 runes yield base premium 50 G (no block applies)");
36	  it.todo("3 runes yield base premium 60 G (block of 3 alike applies)");
37	  it.todo("4 runes yield base premium 100 G (block requires exactly 3)");
38	  it.todo("7 runes yield base premium 175 G (no block)");
39	  it.todo("2 runes + 1 moonstone yield base premium 75 G (different types, no block)");
40	  it.todo("3 runes + 3 moonstones yield base premium 120 G (two separate blocks)");
41	
42	  // ===== Quote: item-specific modifiers =====
43	  it.todo("cursed sword adds 50% surcharge on item base (cursed sword alone: 100 + 50 = 150 base)");
44	  it.todo("highly enchanted sword (enchantment 5) adds 30% surcharge on item base");
45	  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
46	  it.todo("cursed sword with enchantment 5 stacks both surcharges on item base");
47	
48	  // ===== Quote: modifier scope on multi-item policies =====
49	  it.todo("policy with cursed sword + plain amulet: cursed surcharge applies only to cursed item base (newcomer total 231 G)");
50	
51	  // ===== Quote: policy-wide modifiers =====
52	  it.todo("long-standing customer (exactly 2 years) receives 20% loyalty discount on policy base");
53	  it.todo("first insurance (newcomer, no prior contracts) adds 10% surcharge on policy base");
54	  it.todo("follow-up contract gives 15% discount on policy base");
55	
56	  // ===== Quote: rounding in MHPCO's favor =====
57	  it.todo("premium calculation that yields 197.5 G rounds up to 198 G");
58	  it.todo("intermediate amounts kept as fractions; only final premium is rounded");
59	
60	  // ===== Quote: integration examples from spec =====
61	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields premium 165 G");
62	  it.todo("long-standing (3 yrs) customer's second quote with cursed sword (enchantment 7) yields premium 160 G");
63	
64	  // ===== Claim: basic deductible =====
65	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G (full minus 100 deductible)");
66	  it.todo("rune (insurance value 250 G), damage 200 G yields payout 100 G (full minus deductible, no special clauses)");
67	
68	  // ===== Claim: special clauses =====
69	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
70	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
71	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible — both clauses apply)");
72	  it.todo("dragon-material sword exactly enchantment 8, damage 1000 G yields payout 400 G (50% then deductible)");
73	
74	  // ===== Claim: deductible per damage event (multi-item incident) =====
75	  it.todo("dragon attack damages sword (500 G) and amulet (300 G): payout 600 G (deductible per item)");
76	
77	  // ===== Claim: rounding =====
78	  it.todo("payout calculation that yields 350.5 G rounds down to 350 G");
79	
80	  // ===== Claim: insurance sum and cap =====
81	  it.todo("policy of sword + amulet: insurance sum 1600 G, cap 3200 G");
82	  it.todo("policy of sword + 3 runes (a block): insurance sum 1750 G (block discount affects premium only)");
83	  it.todo("cursed sword: cap 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
84	
85	  // ===== Claim: cap exhaustion across successive claims =====
86	  it.todo("sword (cap 2000 G), first claim 1500 G yields payout 1400 G, remainingCap 600 G");
87	  it.todo("sword (cap 2000 G), after first 1500 G claim, second 1500 G claim yields payout 600 G, remainingCap 0 G");
88	
89	  // ===== Claim: multiple items of same type =====
90	  it.todo("policy covers two swords: insurance sum 2000 G, cap 4000 G");
91	  it.todo("dragon attack damages both insured swords: each entry treated separately with own deductible");
92	
93	  // ===== CLI / scenario integration =====
94	  it.todo("scenario with quote then claim returns results array of length 2 with {premium} and {payout, remainingCap}");
95	
96	  // ===== Error cases =====
97	  it.todo("quote with unknown item type (e.g. broomstick) causes CLI to exit non-zero with stderr error");
98	  it.todo("claim referencing damage to an item not in the policy causes CLI to exit non-zero with stderr error");
99	  it.todo("claim with damages array containing more entries of a type than insured causes CLI to exit non-zero");
100	  it.todo("claim with negative damage amount causes CLI to exit non-zero with stderr error");
101	});
